// Extraer datos del body
const body = $input.first().json.body;
const message = body.message || '';
const history = body.history || [];
const locale = body.locale || 'es';
const sessionId = body.sessionId || 'anon';
const systemPrompt = body.systemPrompt || '';

// Mapear locale a idioma completo
const langMap = { es: 'Spanish', en: 'English', pt: 'Portuguese' };
const language = langMap[locale] || 'Spanish';

// Construir system prompt dinámico
const systemContent = systemPrompt || `You are a USCIS asylum officer conducting an asylum interview simulation. 
Respond in ${language} (auto-detect the user's language and always match it).
Be professional but empathetic. Keep responses concise (3-4 sentences max).
Detect inconsistencies in the applicant's answers.
Do not use markdown formatting. Speak naturally.
If the message is 'INICIO_SESION', introduce yourself briefly and ask the first standard asylum question.`;

// Construir historial de mensajes para OpenAI
const openaiMessages = [
  { role: 'system', content: systemContent }
];

// Agregar historial previo (máximo 20 mensajes para no exceder contexto)
const recentHistory = history.slice(-20);
for (const msg of recentHistory) {
  if (msg.role === 'user' || msg.role === 'assistant') {
    openaiMessages.push({
      role: msg.role,
      content: msg.content
    });
  }
}

// Agregar mensaje actual del usuario
if (message && message !== 'INICIO_SESION') {
  openaiMessages.push({ role: 'user', content: message });
}

return [{
  json: {
    messages: openaiMessages,
    sessionId,
    locale
  }
}];

const response = $input.first().json;
const reply = response.choices?.[0]?.message?.content || 'Lo siento, ocurrió un error. Intenta de nuevo.';
const sessionId = $('Preparar Mensajes').first().json.sessionId;
const locale = $('Preparar Mensajes').first().json.locale;

return [{
  json: {
    reply: reply.trim(),
    sessionId,
    locale,
    tokens: response.usage?.total_tokens || 0
  }
}];
